  9	  getName,
 10	  Kebab,
 11	  StorageConsumerModel,
 12	} from '@odf/shared';
 13	import { ODF_OPERATOR } from '@odf/shared/constants/common';
 14	import { getTimeDifferenceInSeconds } from '@odf/shared/details-page/datetime';
 15	import { useFetchCsv, useK8sGet } from '@odf/shared/hooks';
 16	import { ModalKeys } from '@odf/shared/modals';
 17	import { StorageConsumerKind } from '@odf/shared/types';
 18	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 19	import { getOprVersionFromCSV, humanizeBinaryBytes } from '@odf/shared/utils';
 20	import { referenceForModel } from '@odf/shared/utils/common';
 21	import {
 22	  K8sResourceKind,
 23	  ListPageBody,
 24	  ListPageFilter,
 25	  ListPageHeader,
 26	  RedExclamationCircleIcon,
 27	  RowProps,
 28	  TableColumn,
 29	  TableData,
 30	  Timestamp,
 31	  VirtualizedTable,
 32	  YellowExclamationTriangleIcon,
 33	  useActiveColumns,
 34	  useK8sWatchResource,
 35	  useListPageFilter,
 36	  useModal,
 37	} from '@openshift-console/dynamic-plugin-sdk';
 38	import { ModalComponent } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
 39	import * as _ from 'lodash-es';
 40	import { Trans } from 'react-i18next';
 41	import { useNavigate } from 'react-router-dom-v5-compat';
 42	import { Button, Popover, PopoverPosition } from '@patternfly/react-core';
 43	import { sortable } from '@patternfly/react-table';
 44	import { useODFNamespaceSelector } from '../../redux';
 45	import {
 46	  getClientClusterId,
 47	  isLocalClientCluster,
 48	  isClientClusterOnboarded,
 49	} from '../../utils';
 50	import {
 51	  clientHeartBeatFilter,
 52	  getMajorMinorVersion,
 53	  versionMismatchFilter,
 54	} from './list-filter';
 55	import { StorageQuotaUtilizationProgress } from './QuotaUtilizationProgress';
 56	import { RotateKeysModal } from './rotate-keys-modal';
 57	import './client-list.scss';
 58	
 59	export const getClusterName = (client: StorageConsumerKind) => {
 60	  const clusterName = client.status?.client?.clusterName;
 61	  const clientClusterId = getClientClusterId(client);
 62	  let name = '';
 63	  if (!clusterName && !clientClusterId) {
 64	    name = '-';
 65	  } else {
 66	    name = `${clusterName || '-'} (${clientClusterId || '-'})`;
 67	  }
 68	  return name;
 69	};
 70	
 71	const StorageQuotaPopoverContent: React.FC = () => {
 72	  const { t } = useCustomTranslation();
 73	
 74	  return (
 75	    <Trans t={t} ns="plugin__odf-console">
 76	      <p className="pf-v6-u-mb-md">
 77	        The amount of storage allocated to the client cluster for usage.
 78	      </p>
 79	      <p>
 80	        Due to simultaneous usage by multiple client clusters, actual available
 81	        storage may vary affecting your allocated storage quota.
 82	      </p>
 83	    </Trans>
 84	  );
 85	};
 86	
 87	const tableColumns = [
 88	  {
 89	    className: '',
 90	    id: 'name',
 91	  },
 92	  {
 93	    className: 'pf-m-width-20',
 94	    id: 'clusterName',
 95	  },
 96	  {
 97	    className: '',
 98	    id: 'storageQuota',
 99	  },
100	  {
101	    className: '',
102	    id: 'storageQuotaUtilRatio',
103	  },
104	  {
105	    className: '',
106	    id: 'openshiftVersion',
107	  },
108	  {
109	    className: '',
110	    id: 'dataFoundationVersion',
111	  },
112	  {
113	    className: '',
114	    id: 'lastHeartBeat',
115	  },
116	  {
117	    className: Kebab.columnClass,
118	    id: 'kebab',
119	  },
120	];
121	
122	type ClientListProps = {
123	  data: K8sResourceKind[];
124	  unfilteredData: K8sResourceKind[];
125	  loaded: boolean;
126	  loadError: any;
127	  rowData?: any;
128	};
129	
130	const ClientsList: React.FC<ClientListProps> = (props) => {
131	  const { t } = useCustomTranslation();
132	  const clientListTableColumns = React.useMemo<
133	    TableColumn<StorageConsumerKind>[]
134	  >(
135	    () =>
136	      tableColumns.map((tableColumn) => {
137	        const column: TableColumn<StorageConsumerKind> = {
138	          id: tableColumn.id,
139	          props: { className: tableColumn.className },
140	          title: '',
141	          sort: '',
142	          transforms: null,
143	        };
144	        switch (column.id) {
145	          case 'name':
146	            column.title = t('Name');
147	            column.sort = 'metadata.name';
148	            column.transforms = [sortable];
149	            break;
150	          case 'clusterName':
151	            column.title = t('Cluster name (ID)');
152	            column.sort = 'status.client.clusterName';
153	            break;
154	          case 'storageQuota':
155	            column.title = t('Storage quota');
156	            column.sort = 'status.storageQuotaInGiB';
157	            column.props.info = { popover: <StorageQuotaPopoverContent /> };
158	            break;
159	          case 'storageQuotaUtilRatio':
160	            column.title = t('Storage quota utilization ratio');
161	            column.sort = 'status.client.storageQuotaUtilization';
162	            column.transforms = [sortable];
163	            break;
164	          case 'openshiftVersion':
165	            column.title = t('Openshift version');
166	            column.sort = 'status.client.platformVersion';
167	            column.transforms = [sortable];
168	            break;
169	          case 'dataFoundationVersion':
170	            column.title = t('Data Foundation version');
171	            column.sort = 'status.client.operatorVersion';
172	            column.transforms = [sortable];
173	            break;
174	          case 'lastHeartBeat':
175	            column.title = t('Last heartbeat');
176	            column.sort = 'status.lastHeartbeat';
177	            column.transforms = [sortable];
178	            break;
179	          case 'kebab':
180	            break;
181	          default:
182	            throw new Error(`Column not found: ${column.id}`);
183	        }
184	        return column;
185	      }),
186	    [t]
187	  );
188	
189	  const [columns] = useActiveColumns({
190	    columns: clientListTableColumns,
191	    showNamespaceOverride: false,
192	    columnManagementID: null,
193	  });
194	
195	  return (
196	    <VirtualizedTable
197	      {...props}
198	      aria-label={t('StorageConsumers')}
199	      columns={columns}
200	      Row={StorageClientRow}
201	    />
202	  );
203	};
204	
205	const getOpenshiftVersion = (obj: StorageConsumerKind) =>
206	  obj?.status?.client?.platformVersion;
207	
208	const getStorageQuotaUtilizationRatio = (obj: StorageConsumerKind) =>
209	  `${obj?.status?.client?.storageQuotaUtilizationRatio}`;
210	
211	const getDataFoundationVersion = (obj: StorageConsumerKind) =>
212	  obj?.status?.client?.operatorVersion;
213	
214	type LastHeartBeatProps = {
215	  heartbeat: string;
216	};
217	export const LastHeartBeat: React.FC<LastHeartBeatProps> = ({ heartbeat }) => {
218	  const { t } = useCustomTranslation();
219	  const difference = getTimeDifferenceInSeconds(heartbeat);
220	  const Component = (() => {
221	    if (difference > 120 && difference <= 300) {
222	      return YellowExclamationTriangleIcon;
223	    }
224	    if (difference > 300) {
225	      return RedExclamationCircleIcon;
226	    }
227	    return null;
228	  })();
229	  return _.isEmpty(heartbeat) ? (
230	    <>-</>
231	  ) : (
232	    <span>
233	      {Component && <Component />}
234	      &nbsp;
235	      <Timestamp timestamp={heartbeat} omitSuffix simple />
236	      &nbsp;
237	      {t('ago')}
238	    </span>
239	  );
240	};
241	
242	type DataFoundationVersionProps = {
243	  obj: StorageConsumerKind;
244	  currentVersion: string;
245	};
246	
247	const DataFoundationVersion: React.FC<DataFoundationVersionProps> = ({
248	  obj,
249	  currentVersion,
250	}) => {
251	  const { t } = useCustomTranslation();
252	  const clientVersion = getDataFoundationVersion(obj);
253	  const isVersionMismatch =
254	    getMajorMinorVersion(clientVersion) !==
255	    getMajorMinorVersion(currentVersion);
256	  if (_.isEmpty(clientVersion)) {
257	    return <>-</>;
258	  }
259	  return isVersionMismatch ? (
260	    <Popover
261	      position={PopoverPosition.top}
262	      headerContent={t('Client version is out of date')}
263	      bodyContent={t(
264	        'Due to the mismatch in the client and provider version this provider cluster cannot be upgraded.'
265	      )}
266	      enableFlip
267	      maxWidth={'21rem'}
268	    >
269	      <span>
270	        <YellowExclamationTriangleIcon />
271	        <Button
272	          variant="link"
273	          isInline
274	          className="co-status-card__popup"
275	          data-test="health-popover-link"
276	        >
277	          {clientVersion}
278	        </Button>
279	      </span>
280	    </Popover>
281	  ) : (
282	    <>{clientVersion}</>
283	  );
284	};
285	
286	const StorageClientRow: React.FC<
287	  RowProps<
288	    StorageConsumerKind,
289	    {
290	      currentVersion: string;
291	      localClusterId: string;
292	    }
293	  >
294	> = ({ obj, activeColumnIDs, rowData: { currentVersion, localClusterId } }) => {
295	  const { t } = useCustomTranslation();
296	  const humanizedStorageQuota = obj?.spec?.storageQuotaInGiB
297	    ? humanizeBinaryBytes(
298	        obj?.spec?.storageQuotaInGiB,
299	        QuotaSizeUnitOptions[QuotaSize.Gi]
300	      ).string
301	    : t('Unlimited');
302	  const isLocalClient = isLocalClientCluster(obj, localClusterId);
303	  const isClientOnboarded = isClientClusterOnboarded(obj);
304	  const hasDeletionTimestamp = !!obj?.metadata?.deletionTimestamp;
305	  return (
306	    <>
307	      {tableColumns.map((tableColumn) => {
308	        let data: string | JSX.Element;
309	        switch (tableColumn.id) {
310	          case 'name':
311	            data = getName(obj);
312	            break;
313	          case 'clusterName':
314	            data = getClusterName(obj);
315	            break;
316	          case 'storageQuota':
317	            data = humanizedStorageQuota;
318	            break;
319	          case 'storageQuotaUtilRatio':
320	            data = (
321	              <StorageQuotaUtilizationProgress
322	                quotaUtilizationRatio={Number(
323	                  getStorageQuotaUtilizationRatio(obj)
324	                )}
325	                storageQuota={obj?.spec?.storageQuotaInGiB}
326	              />
327	            );
328	            break;
329	          case 'openshiftVersion':
330	            data = getOpenshiftVersion(obj) || '-';
331	            break;
332	          case 'dataFoundationVersion':
333	            data = (
334	              <DataFoundationVersion
335	                obj={obj}
336	                currentVersion={currentVersion}
337	              />
338	            );
339	            break;
340	          case 'lastHeartBeat':
341	            data = <LastHeartBeat heartbeat={obj?.status?.lastHeartbeat} />;
342	            break;
343	          case 'kebab':
344	            data = (
345	              <Kebab
346	                extraProps={{
347	                  resource: obj,
348	                  resourceModel: StorageConsumerModel,
349	                  forceDeletion: true,
350	                }}
351	                customKebabItems={[
352	                  {
353	                    key: ModalKeys.EDIT_RES,
354	                    value: t('Edit storage quota'),
355	                    component: React.lazy(
356	                      () => import('./update-storage-quota-modal')
357	                    ),
358	                    isDisabled: isLocalClient || hasDeletionTimestamp,
359	                  },
360	                  {
361	                    key: 'GENERATE_ONBOARDING_TOKEN',
362	                    value: t('Generate client onboarding token'),
363	                    isDisabled:
364	                      isLocalClient ||
365	                      isClientOnboarded ||
366	                      hasDeletionTimestamp,
367	                    component: React.lazy(() =>
368	                      import('./onboarding-modal').then((m) => ({
369	                        default: m.ClientOnBoardingModal,
370	                      }))
371	                    ),
372	                  },
373	                  {
374	                    key: 'DISTRIBUTE_RESOURCES',
375	                    value: t('Distribute resources'),
376	                    isDisabled: isLocalClient || hasDeletionTimestamp,
377	                    component: React.lazy(
378	                      () =>
379	                        import(
380	                          '../../modals/ResourceDistributionModal/ResourceDistributionModal'
381	                        )
382	                    ),
383	                  },
384	                  {
385	                    key: ModalKeys.DELETE,
386	                    value: t('Delete StorageConsumer'),
387	                    isDisabled: isLocalClient,
388	                    component: React.lazy(
389	                      () => import('./remove-client-modal')
390	                    ),
391	                  },
392	                ]}
393	                hideItems={[ModalKeys.EDIT_LABELS, ModalKeys.EDIT_ANN]}
394	              />
395	            );
396	            break;
397	          default:
398	            throw new Error(`Data not found for column: ${tableColumn.id}`);
399	        }
400	        return (
401	          <TableData {...tableColumn} activeColumnIDs={activeColumnIDs}>
402	            {data}
403	          </TableData>
404	        );
405	      })}
406	    </>
407	  );
408	};
409	
410	type ClientListPageProps = {
411	  showTitle?: boolean;
412	  namespace?: string;
413	  selector?: any;
414	  hideLabelFilter?: boolean;
415	  hideNameLabelFilters?: boolean;
416	  hideColumnManagement?: boolean;
417	};
418	
419	export const ClientListPage: React.FC<ClientListPageProps> = () => {
420	  const { t } = useCustomTranslation();
421	  const launchModal = useModal();
422	  const [storageClients, loaded, loadError] = useK8sWatchResource<
423	    StorageConsumerKind[]
424	  >({
425	    kind: referenceForModel(StorageConsumerModel),
426	    isList: true,
427	  });
428	
429	  const [cv, cvLoaded, cvLoadError] = useK8sGet<ClusterVersionKind>(
430	    ClusterVersionModel,
431	    'version'
432	  );
433	  const localClusterId = cv?.spec?.clusterID;
434	
435	  const { odfNamespace, isNsSafe } = useODFNamespaceSelector();
436	
437	  const [csv, csvLoaded, csvLoadError] = useFetchCsv({
438	    specName: ODF_OPERATOR,
439	    namespace: odfNamespace,
440	    startPollingInstantly: isNsSafe,
441	  });
442	  const serviceVersion = getOprVersionFromCSV(csv);
443	
444	  const rowFilters = React.useMemo(() => {
445	    const customFilters = [
446	      clientHeartBeatFilter(t),
447	      versionMismatchFilter(t, serviceVersion),
448	    ];
449	    return customFilters;
450	  }, [t, serviceVersion]);
451	
452	  const [data, filteredData, onFilterChange] = useListPageFilter(
453	    storageClients,
454	    rowFilters
455	  );
456	
457	  const launchModalOnClick = (modalComponent: ModalComponent) => () => {
458	    launchModal(modalComponent, { isOpen: true });
459	  };
460	
461	  const navigate = useNavigate();
462	
463	  return (
464	    <>
465	      <ListPageHeader title={t('Storage Consumers')}>
466	        <Button
467	          variant="primary"
468	          className="pf-v6-u-mr-sm"
469	          onClick={() => navigate('/odf/storage-consumers/create')}
470	        >
471	          {t('Create Storage Consumer')}
472	        </Button>
473	        <Button
474	          variant="tertiary"
475	          onClick={launchModalOnClick(RotateKeysModal)}
476	        >
477	          {t('Rotate signing keys')}
478	        </Button>
479	      </ListPageHeader>
480	      <ListPageBody>
481	        <ListPageFilter
482	          data={data}
483	          loaded={loaded && csvLoaded && cvLoaded}
484	          onFilterChange={onFilterChange}
485	          hideColumnManagement={true}
486	          rowFilters={rowFilters}
487	        />
488	        <ClientsList
489	          data={filteredData}
490	          unfilteredData={storageClients}
491	          loaded={loaded && csvLoaded}
492	          loadError={loadError || csvLoadError || cvLoadError}
493	          rowData={{ currentVersion: serviceVersion, localClusterId }}
494	        />
495	      </ListPageBody>
496	    </>
497	  );
498	};

